// --- Helper Components ---

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }) => {
  if (!isOpen) return null;
  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modalContent} onClick={e => e.stopPropagation()}>
        <button onClick={onClose} style={{ position: 'absolute', top: '24px', right: '24px', background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#999' }}>×</button>
        <h2 style={{ fontFamily: 'var(--font-heading)', fontSize: '32px', marginBottom: '24px', color: '#1a1a1a' }}>{title}</h2>
        {children}
      </div>
    </div>
  );
};

// --- Tool Components (Logic ported from previous turn) ---

const Calculator = () => {
  const [display, setDisplay] = useState('0');

  const handleBtn = (val: string) => {
    if (val === 'C') setDisplay('0');
    else if (val === '=') {
      try {
        // eslint-disable-next-line no-eval
        setDisplay(eval(display).toString());
      } catch { setDisplay('Error'); }
    } else {
      setDisplay(prev => prev === '0' ? val : prev + val);
    }
  };

  const btns = ['C', '(', ')', '/', '7', '8', '9', '*', '4', '5', '6', '-', '1', '2', '3', '+', '0', '.', '='];

  return (
    <div>
      <div style={{ background: '#1a1a1a', color: 'white', padding: '24px', borderRadius: '16px', fontSize: '32px', textAlign: 'right', marginBottom: '20px', fontFamily: 'monospace' }}>{display}</div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '10px' }}>
        {btns.map(b => (
          <button key={b} onClick={() => handleBtn(b)} style={{ padding: '20px', borderRadius: '12px', border: 'none', background: b === '=' ? '#9b6dff' : '#f0f0f0', color: b === '=' ? 'white' : '#333', fontSize: '18px', fontWeight: 'bold', cursor: 'pointer' }}>{b}</button>
        ))}
      </div>
    </div>
  );
};

const BMITracker = () => {
  const [height, setHeight] = useState('');
  const [weight, setWeight] = useState('');
  const [result, setResult] = useState<{bmi: string, category: string} | null>(null);

  const calculate = () => {
    const h = parseFloat(height) / 100;
    const w = parseFloat(weight);
    if (h && w) {
      const bmi = w / (h * h);
      let cat = '';
      if (bmi < 18.5) cat = 'Underweight';
      else if (bmi < 25) cat = 'Normal';
      else if (bmi < 30) cat = 'Overweight';
      else cat = 'Obese';
      setResult({ bmi: bmi.toFixed(1), category: cat });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Height (cm)" type="number" value={height} onChange={e => setHeight(e.target.value)} />
      <input style={styles.input} placeholder="Weight (kg)" type="number" value={weight} onChange={e => setWeight(e.target.value)} />
      <button style={styles.button} onClick={calculate}>Analyze Metrics</button>
      {result && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '48px', fontWeight: 800, color: '#9b6dff' }}>{result.bmi}</div>
          <div style={{ fontSize: '14px', textTransform: 'uppercase', letterSpacing: '2px', color: '#666' }}>{result.category}</div>
        </div>
      )}
    </div>
  );
};

const CurrencyForge = () => {
  const [amount, setAmount] = useState('1');
  const [from, setFrom] = useState('USD');
  const [to, setTo] = useState('EUR');
  const [res, setRes] = useState<string | null>(null);

  const rates: any = { USD: 1, EUR: 0.92, GBP: 0.79, JPY: 149.50 }; // Simplified for demo

  const convert = () => {
    const val = (parseFloat(amount) / rates[from]) * rates[to];
    setRes(val.toFixed(2));
  };

  return (
    <div>
      <input style={styles.input} type="number" value={amount} onChange={e => setAmount(e.target.value)} />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
        <select style={styles.input} value={from} onChange={e => setFrom(e.target.value)}>
          {Object.keys(rates).map(c => <option key={c} value={c}>{c}</option>)}
        </select>
        <select style={styles.input} value={to} onChange={e => setTo(e.target.value)}>
          {Object.keys(rates).map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>
      <button style={styles.button} onClick={convert}>Forge Currency</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff' }}>{res} {to}</div>
        </div>
      )}
    </div>
  );
};

const MortgageMaster = () => {
  const [amount, setAmount] = useState('');
  const [rate, setRate] = useState('');
  const [years, setYears] = useState('');
  const [payment, setPayment] = useState<string | null>(null);

  const calc = () => {
    const p = parseFloat(amount);
    const r = parseFloat(rate) / 100 / 12;
    const n = parseFloat(years) * 12;
    if (p && r && n) {
      const m = p * (r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1);
      setPayment(m.toFixed(2));
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Loan Amount ($)" type="number" value={amount} onChange={e => setAmount(e.target.value)} />
      <input style={styles.input} placeholder="Interest Rate (%)" type="number" value={rate} onChange={e => setRate(e.target.value)} />
      <input style={styles.input} placeholder="Loan Term (Years)" type="number" value={years} onChange={e => setYears(e.target.value)} />
      <button style={styles.button} onClick={calc}>Calculate Repayment</button>
      {payment && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '14px', color: '#666' }}>MONTHLY PAYMENT</div>
          <div style={{ fontSize: '40px', fontWeight: 800, color: '#9b6dff' }}>${payment}</div>
        </div>
      )}
    </div>
  );
};

