const UnitUnifier = () => {
  const [type, setType] = useState('length');
  const [val, setVal] = useState('');
  const [from, setFrom] = useState('m');
  const [to, setTo] = useState('ft');
  const [res, setRes] = useState<string | null>(null);

  const units: any = {
    length: { m: 1, km: 1000, cm: 0.01, mm: 0.001, ft: 0.3048, in: 0.0254, mi: 1609.34 },
    weight: { kg: 1, g: 0.001, lb: 0.453592, oz: 0.0283495 },
    temp: { C: 'c', F: 'f', K: 'k' } // Special handling
  };

  const handleTypeChange = (t: string) => {
    setType(t);
    const keys = Object.keys(units[t]);
    setFrom(keys[0]);
    setTo(keys[1] || keys[0]);
    setRes(null);
  };

  const calc = () => {
    const v = parseFloat(val);
    if (isNaN(v)) return;

    if (type === 'temp') {
      let tempInC = v;
      if (from === 'F') tempInC = (v - 32) * 5/9;
      if (from === 'K') tempInC = v - 273.15;

      let resTemp = tempInC;
      if (to === 'F') resTemp = (tempInC * 9/5) + 32;
      if (to === 'K') resTemp = tempInC + 273.15;
      setRes(resTemp.toFixed(2));
    } else {
      const base = v * units[type][from];
      const result = base / units[type][to];
      setRes(result.toFixed(4));
    }
  };

  return (
    <div>
      <select style={styles.select} value={type} onChange={e => handleTypeChange(e.target.value)}>
        <option value="length">Length</option>
        <option value="weight">Weight</option>
        <option value="temp">Temperature</option>
      </select>
      <input style={styles.input} placeholder="Value" type="number" value={val} onChange={e => setVal(e.target.value)} />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
        <select style={styles.select} value={from} onChange={e => setFrom(e.target.value)}>
          {Object.keys(units[type]).map(u => <option key={u} value={u}>{u}</option>)}
        </select>
        <select style={styles.select} value={to} onChange={e => setTo(e.target.value)}>
          {Object.keys(units[type]).map(u => <option key={u} value={u}>{u}</option>)}
        </select>
      </div>
      <button style={styles.button} onClick={calc}>Unify Units</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff' }}>{res} {to}</div>
        </div>
      )}
    </div>
  );
};

const WealthWeaver = () => {
  const [initial, setInitial] = useState('');
  const [monthly, setMonthly] = useState('');
  const [rate, setRate] = useState('');
  const [years, setYears] = useState('');
  const [res, setRes] = useState<any>(null);

  const calc = () => {
    const p = parseFloat(initial);
    const m = parseFloat(monthly);
    const r = parseFloat(rate) / 100 / 12;
    const n = parseFloat(years) * 12;

    if (!isNaN(p) && !isNaN(m) && !isNaN(r) && !isNaN(n)) {
      const fv = p * Math.pow(1+r, n) + m * ((Math.pow(1+r, n) - 1) / r);
      const invested = p + (m * n);
      setRes({ fv: fv.toFixed(2), interest: (fv - invested).toFixed(2) });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Initial Deposit ($)" type="number" value={initial} onChange={e => setInitial(e.target.value)} />
      <input style={styles.input} placeholder="Monthly Contribution ($)" type="number" value={monthly} onChange={e => setMonthly(e.target.value)} />
      <input style={styles.input} placeholder="Annual Return (%)" type="number" value={rate} onChange={e => setRate(e.target.value)} />
      <input style={styles.input} placeholder="Years to Grow" type="number" value={years} onChange={e => setYears(e.target.value)} />
      <button style={styles.button} onClick={calc}>Weave Wealth</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '12px', color: '#666' }}>FUTURE VALUE</div>
          <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff' }}>${res.fv}</div>
          <div style={{ fontSize: '12px', color: '#666', marginTop: '8px' }}>Total Interest Earned: ${res.interest}</div>
        </div>
      )}
    </div>
  );
};

const AgeAnalyzer = () => {
  const [dob, setDob] = useState('');
  const [age, setAge] = useState<any>(null);

  const calc = () => {
    const birth = new Date(dob);
    const now = new Date();
    if (isNaN(birth.getTime())) return;

    let years = now.getFullYear() - birth.getFullYear();
    let months = now.getMonth() - birth.getMonth();
    let days = now.getDate() - birth.getDate();

    if (months < 0 || (months === 0 && days < 0)) {
      years--;
      months += 12;
    }
    if (days < 0) {
      const prevMonth = new Date(now.getFullYear(), now.getMonth(), 0);
      days += prevMonth.getDate();
      months--;
    }

    setAge({ years, months, days });
  };

  return (
    <div>
      <input style={styles.input} type="date" value={dob} onChange={e => setDob(e.target.value)} />
      <button style={styles.button} onClick={calc}>Analyze Chronology</button>
      {age && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff' }}>{age.years} Years</div>
          <div style={{ fontSize: '16px', color: '#666' }}>{age.months} months, {age.days} days</div>
        </div>
      )}
    </div>
  );
};

const LifeLoom = () => {
  const [lmp, setLmp] = useState('');
  const [dueDate, setDueDate] = useState('');

  const calc = () => {
    const d = new Date(lmp);
    if (!isNaN(d.getTime())) {
      d.setDate(d.getDate() + 280); // Naegele's rule (approx)
      setDueDate(d.toDateString());
    }
  };

  return (
    <div>
      <label style={{display: 'block', marginBottom: '8px', fontSize: '12px', fontWeight: 700}}>First Day of Last Period</label>
      <input style={styles.input} type="date" value={lmp} onChange={e => setLmp(e.target.value)} />
      <button style={styles.button} onClick={calc}>Estimate Arrival</button>
      {dueDate && (
