const Calculator = () => {
  const [display, setDisplay] = useState('0');
  const [equation, setEquation] = useState('');

  const handleBtn = (val: string) => {
    if (val === 'C') {
      setDisplay('0');
      setEquation('');
    } else if (val === '=') {
      try {
        const result = eval(display.replace('x', '*'));
        setEquation(display);
        setDisplay(result.toString());
      } catch {
        setDisplay('Error');
        setEquation('');
      }
    } else if (['+', '-', '*', '/'].includes(val)) {
       setDisplay(prev => prev + ' ' + val + ' ');
    } else {
      setDisplay(prev => prev === '0' ? val : prev + val);
    }
  };

  const btns = [
    { label: 'C', type: 'clear' }, { label: '(', type: 'op' }, { label: ')', type: 'op' }, { label: '/', type: 'op' },
    { label: '7', type: 'num' }, { label: '8', type: 'num' }, { label: '9', type: 'num' }, { label: '*', type: 'op' },
    { label: '4', type: 'num' }, { label: '5', type: 'num' }, { label: '6', type: 'num' }, { label: '-', type: 'op' },
    { label: '1', type: 'num' }, { label: '2', type: 'num' }, { label: '3', type: 'num' }, { label: '+', type: 'op' },
    { label: '0', type: 'num' }, { label: '.', type: 'num' }, { label: '=', type: 'eq', span: 2 }
  ];

  return (
    <div style={{ padding: '10px' }}>
      <div style={{ 
        background: '#f8f7ff', 
        borderRadius: '24px', 
        padding: '32px', 
        marginBottom: '24px', 
        textAlign: 'right', 
        boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.02)',
        border: '1px solid #e0d7ff'
      }}>
        <div style={{ height: '24px', color: '#999', fontSize: '14px', fontFamily: 'monospace' }}>{equation}</div>
        <div style={{ fontSize: '48px', fontWeight: 800, color: '#9b6dff', fontFamily: 'var(--font-heading)' }}>{display}</div>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px' }}>
        {btns.map((b, i) => (
          <button 
            key={i} 
            onClick={() => handleBtn(b.label)} 
            style={{ 
              gridColumn: b.span ? `span ${b.span}` : 'span 1',
              padding: '24px', 
              borderRadius: '20px', 
              border: b.type === 'num' ? '1px solid #e0d7ff' : 'none',
              background: b.type === 'eq' ? '#9b6dff' : b.type === 'op' ? '#f0ebff' : b.type === 'clear' ? '#ffe0e0' : 'white', 
              color: b.type === 'eq' ? 'white' : b.type === 'op' ? '#9b6dff' : b.type === 'clear' ? '#ff4757' : '#1a1a1a', 
              fontSize: '20px', 
              fontWeight: 700, 
              cursor: 'pointer',
              transition: 'transform 0.1s',
              boxShadow: b.type === 'num' ? '0 4px 0 #f0f0f0' : 'none'
            }}
            onMouseDown={(e) => e.currentTarget.style.transform = 'scale(0.95)'}
            onMouseUp={(e) => e.currentTarget.style.transform = 'scale(1)'}
            onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
          >
            {b.label}
          </button>
        ))}
      </div>
    </div>
  );
};

const BMITracker = () => {
  const [height, setHeight] = useState('');
  const [weight, setWeight] = useState('');
  const [result, setResult] = useState<{bmi: string, category: string} | null>(null);

  const calculate = () => {
    const h = parseFloat(height) / 100;
    const w = parseFloat(weight);
    if (h && w) {
      const bmi = w / (h * h);
      let cat = '';
      if (bmi < 18.5) cat = 'Underweight';
      else if (bmi < 25) cat = 'Normal';
      else if (bmi < 30) cat = 'Overweight';
      else cat = 'Obese';
      setResult({ bmi: bmi.toFixed(1), category: cat });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Height (cm)" type="number" value={height} onChange={e => setHeight(e.target.value)} />
      <input style={styles.input} placeholder="Weight (kg)" type="number" value={weight} onChange={e => setWeight(e.target.value)} />
      <button style={styles.button} onClick={calculate}>Calculate BMI</button>
      {result && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '48px', fontWeight: 800, color: '#9b6dff' }}>{result.bmi}</div>
          <div style={{ fontSize: '14px', textTransform: 'uppercase', letterSpacing: '2px', color: '#666' }}>{result.category}</div>
        </div>
      )}
    </div>
  );
};

