          </div>
        ))}
      </div>
    </div>
  );
};

const TipCalculator = () => {
  const [bill, setBill] = useState('');
  const [tip, setTip] = useState('15');
  const [people, setPeople] = useState('1');
  const [res, setRes] = useState<any>(null);

  const calc = () => {
    const b = parseFloat(bill);
    const t = parseFloat(tip) / 100;
    const p = parseFloat(people);

    if (b && p) {
      const tipAmount = b * t;
      const total = b + tipAmount;
      const perPerson = total / p;
      setRes({ tip: tipAmount.toFixed(2), total: total.toFixed(2), perPerson: perPerson.toFixed(2) });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Bill Amount ($)" type="number" value={bill} onChange={e => setBill(e.target.value)} />
      <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
        {[10, 15, 18, 20].map(p => (
          <button key={p} onClick={() => setTip(p.toString())} style={{ ...styles.button, marginTop: 0, background: tip === p.toString() ? '#9b6dff' : '#e0d7ff', color: tip === p.toString() ? 'white' : '#9b6dff' }}>{p}%</button>
        ))}
      </div>
      <input style={styles.input} placeholder="Tip % (Custom)" type="number" value={tip} onChange={e => setTip(e.target.value)} />
      <input style={styles.input} placeholder="Split with (People)" type="number" value={people} onChange={e => setPeople(e.target.value)} />
      <button style={styles.button} onClick={calc}>Calculate Tip</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
             <span>Tip Amount:</span> <strong>${res.tip}</strong>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
             <span>Total Bill:</span> <strong>${res.total}</strong>
          </div>
          <div style={{ borderTop: '2px dashed #e0d7ff', paddingTop: '10px' }}>
             <div style={{ fontSize: '12px', color: '#666' }}>PER PERSON</div>
             <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff' }}>${res.perPerson}</div>
          </div>
        </div>
      )}
    </div>
  );
};

const DiscountDecoder = () => {
  const [price, setPrice] = useState('');
  const [discount, setDiscount] = useState('');
  const [res, setRes] = useState<any>(null);

  const calc = () => {
    const p = parseFloat(price);
    const d = parseFloat(discount);
    if (!isNaN(p) && !isNaN(d)) {
      const save = p * (d/100);
      const final = p - save;
      setRes({ save: save.toFixed(2), final: final.toFixed(2) });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Original Price ($)" type="number" value={price} onChange={e => setPrice(e.target.value)} />
      <input style={styles.input} placeholder="Discount (%)" type="number" value={discount} onChange={e => setDiscount(e.target.value)} />
      <button style={styles.button} onClick={calc}>Calculate Discount</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '14px', color: '#666' }}>FINAL PRICE</div>
          <div style={{ fontSize: '40px', fontWeight: 800, color: '#9b6dff' }}>${res.final}</div>
          <div style={{ fontSize: '14px', color: '#2ecc71', marginTop: '5px' }}>You Save: ${res.save}</div>
        </div>
      )}
    </div>
  );
};

const SalarySlicer = () => {
  const [hourly, setHourly] = useState('');
  const [hours, setHours] = useState('40');
  const [res, setRes] = useState<any>(null);

  const calc = () => {
    const h = parseFloat(hourly);
    const hrs = parseFloat(hours);
    if (h && hrs) {
      const weekly = h * hrs;
      const yearly = weekly * 52;
      const monthly = yearly / 12;
      setRes({ weekly: weekly.toLocaleString(), monthly: monthly.toLocaleString(undefined, {maximumFractionDigits: 0}), yearly: yearly.toLocaleString() });
    }
  };

  return (
    <div>
      <input style={styles.input} placeholder="Hourly Rate ($)" type="number" value={hourly} onChange={e => setHourly(e.target.value)} />
      <input style={styles.input} placeholder="Hours per Week" type="number" value={hours} onChange={e => setHours(e.target.value)} />
      <button style={styles.button} onClick={calc}>Calculate Salary</button>
      {res && (
        <div style={styles.resultBox}>
          <div style={{ fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>ANNUAL INCOME</div>
          <div style={{ fontSize: '32px', fontWeight: 800, color: '#9b6dff', marginBottom: '16px' }}>${res.yearly}</div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '14px' }}>
            <span>Monthly: <strong>${res.monthly}</strong></span>
            <span>Weekly: <strong>${res.weekly}</strong></span>
          </div>
        </div>
      )}
    </div>
  );
};

